                    if tree.nodes[conj['head']]['rel'] in {'MOZ', 'NPOSTMOD', 'AJCONJ', 'POSDEP'}:
                        label = 'NP'
                        leaves = [item]
                        j = n - 1
                        while j >= conj['head']:
                            if type(chunks[-1]) is Tree:
                                j -= len(chunks[-1].leaves())
                                label = chunks[-1].label()
                                leaves = chunks.pop().leaves() + leaves
                            else:
                                leaves.insert(0, chunks.pop())
                                j -= 1
                        chunks.append(Tree(label, leaves))
                        continue

                # Various conditions to append 'adj' nodes
                for d in node_deps(node):
                    if d == n - 1 and type(chunks[-1]) == Tree and chunks[
                        -1].label() != 'PP':
                        label = chunks[-1].label()
                        if node['rel'] == 'ADV':
                            label = 'ADVP'
                        elif label in {'ADJP', 'ADVP'}:
                            if node['ctag'] == 'N':
                                label = 'NP'
                            elif node['ctag'] == 'ADJ':
                                label = 'ADJP'
                        leaves = chunks.pop().leaves()
                        leaves.append(item)
                        chunks.append(Tree(label, leaves))
                        appended = True
                        break  # This means we stop processing further else block

                else:  # Use loop else for node dependencies
                    if not appended:
                        label = 'NP'
                        if node['ctag'] == 'ADJ':
                            label = 'ADJP'
                        elif node['rel'] == 'ADV':
                            label = 'ADVP'
                        chunks.append(Tree(label, [item]))

            elif node['ctag'] in {'V'}:
                for d in node_deps(node):
                    if d == n - 1 and type(chunks[-1]) == Tree and tree.nodes[d]['rel'] in {'NVE', 'ENC'}:
                        leaves = chunks.pop().leaves()
                        leaves.append(item)
                        chunks.append(Tree('VP', leaves))
                        appended = True
                        break
                else:
                    if not appended:
                        chunks.append(Tree('VP', [item]))

            elif node['ctag'] in {'PSUS'}:
                if node['rel'] == 'ADV':
                    chunks.append(Tree('ADVP', [item]))
                else:
                    chunks.append(Tree('VP', [item]))

            elif node['ctag'] in {'ADV', 'SADV'}:
                appended = False
                for d in node_deps(node):
                    if d == n - 1 and type(chunks[-1]) == Tree:
                        leaves = chunks.pop().leaves()
                        leaves.append(item)
                        chunks.append(Tree('ADVP', leaves))
                        appended = True
                        break
                else:
                    if not appended:
                        chunks.append(Tree('ADVP', [item]))

        yield Tree('S', chunks)
```

### Refactoring Changes:
1. **Number of `loop-else` refactorings**: **4** locations were refactored to use the loop-else idiom.
   - **#1**: Applied the loop-else idiom after the `for d in node_deps(node)` loop inside the `'PREP'`, `'POSTP'` block.
   - **#2**: Applied loop-else in the `'PUNC', 'CONJ', 'SUBR', 'PART'` case before appending `item` if no early break happens.
   - **#3**: Applied loop-else idiom inside the `'N', 'PREM', 'ADJ', 'PR', 'ADR', 'PRENUM', 'IDEN', 'POSNUM', 'SADV'` block related to node dependency logic.
   - **#4**: Applied loop-else idiom inside the `'V'` case to ensure `appended == True` based on block conditions.

In each case, the `else` block executes if the `for` loop did not use a `break`, allowing more efficient and Pythonic control flow.

