def _strip_empty(self, lines: List[str]) -> List[str]:
    if lines:
        # Find the start index
        for start, line in enumerate(lines):
            if line:
                break
        else:
            # This else corresponds to the case where the loop didn't 'break', meaning no non-empty line was found
            return []

        # Find the end index
        for end in reversed(range(len(lines))):
            if lines[end]:
                break
        else:
            # This else is theoretically redundant since we already found 'start', 
            # but adding it for consistency with 'for-else' idiom
            return []

        # Slice the lines between start and end
        if start > 0 or end + 1 < len(lines):
            lines = lines[start:end + 1]

    return lines

