def __getattr__(self, item):
    if isinstance(item, STRING_TYPES):
        if item == '_state':
            return object.__getattr__(self, item)
        item = ''.join(item.split()).lower()

        for attr in self._state.attributes.keys():
            if item == attr.lower():
                # Found a matching key
                return self._state.attributes[attr]
        else:  # Did not break from the loop, so move to aliases
            for attr in self._state.attributes.aliases():
                if item == attr.lower():
                    return self._state.attributes[attr]

        for attr in self._state.attributes.keys():
            if item + ';binary' == attr.lower():
                # Found a matching binary key
                return self._state.attributes[attr]
        else:
            for attr in self._state.attributes.aliases():
                if item + ';binary' == attr.lower():
                    return self._state.attributes[attr]

        for attr in self._state.attributes.keys():
            if item + ';range' in attr.lower():
                # Found a matching range key
                return self._state.attributes[attr]
        else:
            for attr in self._state.attributes.aliases():
                if item + ';range' in attr.lower():
                    return self._state.attributes[attr]

        # If no attribute was found, raise the attribute error
        error_message = 'attribute \'%s\' not found' % item
        if log_enabled(ERROR):
            log(ERROR, '%s for <%s>', error_message, self)
        raise LDAPCursorAttributeError(error_message)

    error_message = 'attribute name must be a string'
    if log_enabled(ERROR):
        log(ERROR, '%s for <%s>', error_message, self)
    raise LDAPCursorAttributeError(error_message)
```

### Explanation:
- The number of refactorings that involved using the loop-else idiom is **five**.
  - Each check for `attr_found` after a `for` loop was refactored into the `else` block of the loop.
  - When no `break` statement occurs in the loop (i.e., no attribute was found), the associated `else` block is executed, which allows us to proceed with the next set of checks.

### Benefits of the Refactor:
- The code is cleaner and less repetitive by using `for-else`.
- The intent becomes clearer: each set of attribute matching attempts (keys or aliases) performs as early-exit checks and returns when a match is found without needing to have additional `if not attr_found` checks.

